                          aria-label="Eliminar chat"
                        >
                          <Trash2 size={14} />
                        </button>
                      ) : null}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </main>

      <BottomNav active="chats" onNavigate={onNavigate} />
    </div>
  );
