  if (!compact) return 'Nuevo chat';
  return compact.length > 80 ? `${compact.slice(0, 77)}...` : compact;
}

function sanitizeConversationModel(rawValue) {
  if (typeof rawValue !== 'string') return '';
  return rawValue.trim();
